+function createEnabledBundleConfig(pluginIds: string[]): OpenClawConfig {
+  return {
+    plugins: {
+      entries: Object.fromEntries(pluginIds.map((pluginId) => [pluginId, { enabled: true }])),
+    },
+  };
+}
